//-------------------------------------------------------------------------
scwin.f_create = function () {
  // 조회조건 DataSet 초기화
  ds_search.setEmptyValue();

  // 반출(COPINO) DataSet 초기화
  ds_resultsCopinoOut.removeAll();
  acb_fullEmptyClsCd1.setValue("");
  ds_resultsCopinoOut.insertRow();
  dm_resultsCopinoOut.setJSON(ds_resultsCopinoOut.getRowJSON(0));

  // 반입(COPINO) DataSet 초기화
  ds_resultsCopinoIn.removeAll();
  acb_fullEmptyClsCd2.setValue("");
  ds_resultsCopinoIn.insertRow();
  dm_resultsCopinoIn.setJSON(ds_resultsCopinoIn.getRowJSON(0));

  // 조회조건 초기화
  scwin.f_FieldClear();

  // 초기값 설정
  scwin.f_defaultValue();
  $c.gus.cfEnableBtnOnly($p, [btn_create, btn_save]); // 버튼 활성화

  cbx_crryOutCopino.checkAll(true);
  cbx_crryInCopino.checkAll(true);
  scwin.f_switchTransYn(1);
  scwin.f_switchTransYn(2);
  ed_sealNo2.setMandatory(false);
  ed_sealNo2.setReadOnly(false);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tb_srchCond);
  ica_crryinoutDt1.setValue(scwin.dateStr);
  ica_crryinoutDt2.setValue(scwin.dateStr);
  ed_crryinoutHh1.setValue(scwin.dateTime);
  ed_crryinoutHh2.setValue(scwin.dateTime);
};

//-------------------------------------------------------------------------
// 전송여부 switch
//-------------------------------------------------------------------------
scwin.f_switchTransYn = function (gubun) {
  if (gubun == 1) {
    if (cbx_crryOutCopino.getValue() == "Y") {
      //chk_crryOutCopino.checked 
      $c.gus.cfEnableObjects($p, [tb_crryOutCopino]);
    } else {
      $c.gus.cfDisableObjects($p, [tb_crryOutCopino]);
    }
  } else if (gubun == 2) {
    if (cbx_crryInCopino.getValue() == "Y") {
      //chk_crryInCopino.checked
      $c.gus.cfEnableObjects($p, [tb_crryInCopino]);
    } else {
      $c.gus.cfDisableObjects($p, [tb_crryInCopino]);
    }
  }
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function (gubun) {
  if ((ed_vehclIdCardNo.getValue() == null || ed_vehclIdCardNo.getValue() == "") && (ed_cntrNo.getValue() == null || ed_cntrNo.getValue() == "")) {
    $c.win.alert($p, "조회시 차량 ID와 CNTR_NO 중 둘중에 하나 기입해야 합니다.");
    return false;
  }
  if (ed_vehclIdCardNo.getValue() != null && ed_vehclIdCardNo.getValue() != "") {
    if (ed_vehclIdCardNo.getValue().length != 8) {
      $c.win.alert($p, "조회시 차량 ID는  8자리를  기입해야 합니다.");
      return false;
    }
  }
  if (ed_cntrNo.getValue() != null && ed_cntrNo.getValue() != "") {
    if (ed_cntrNo.getValue().length != 11) {
      $c.win.alert($p, "조회시 컨테이너는 번호는 11자리를  기입해야 합니다.");
      return false;
    }
  }
  if (gubun == null || gubun == "" || gubun == 0) {
    ds_resultsCopinoOut.removeAll(); //ds_resultsCopinoOut.ClearData();
    ds_resultsCopinoIn.removeAll(); //ds_resultsCopinoIn.ClearData();

    scwin.rowFlag = ""; // 등록, 수정 후 저장 안하고 다른 master row 선택 불가능 구분자

    $c.sbm.execute($p, sbm_retrieve);
  } else {
    if (cbx_crryInCopino.getValue() != "Y") {
      ds_resultsCopinoIn2.removeAll();
      if (cbx_crryOutCopino.getValue() == "Y") {
        var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        $c.gus.cfCopyDataSet($p, ds_resultsCopinoOut2, ds_resultsCopinoOut, v_features);
        $c.sbm.execute($p, sbm_retrieve2);
      }
    }
    if (cbx_crryOutCopino.getValue() != "Y") {
      ds_resultsCopinoOut2.removeAll();
      if (cbx_crryInCopino.getValue() == "Y") {
        var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        $c.gus.cfCopyDataSet($p, ds_resultsCopinoIn2, ds_resultsCopinoIn, v_features);
        $c.sbm.execute($p, sbm_retrieve2);
      }
    }
  }
};

