//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    // inObj가 코드 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp2 = function (inObj, pairObj, disGubun, isCode, refObj) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    $c.gus.cfClearPairObj($p, refObj);
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);
  $c.gus.cfClearPairObj($p, refObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    // inObj가 코드 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};
scwin.udc_ed_transDstFrom1_callBackFunc = function (ret) {
  if (ret != null) {
    console.log("▶▶▶▶ udc_ed_transDstFrom1_callBackFunc not null ▶▶▶▶");
    if (ret[0] != "N/A") {
      ed_transDstFrom1.setValue(ret[0]);
      scwin.hid_transDstFromNm1 = ret[1];
      scwin.hid_transDstFromWrkPlCd1 = ret[2];
    }
  } else {
    console.log("▶▶▶▶ udc_ed_transDstFrom1_callBackFunc ▶▶▶▶");
    ed_transDstFrom1.setValue("");
    scwin.hid_transDstFromNm1 = "";
    scwin.hid_transDstFromWrkPlCd1 = "";
  }
  if (!$c.gus.cfIsNull($p, ed_transDstFrom1.getValue())) {
    // 출발지 설정
    scwin.hid_startPoint1 = ed_transDstFrom1.getValue();
    if (ed_transDstFrom1.getValue() == "6P42") {
      // CY 가 울산정일부두(6P42) 인 경우 : 화주 필수 입력
      // ed_mchtCd1.mandatory = "true";
      // ed_mchtCd1.validExp="화주:yes";
      ed_mchtCd1.mandatoryCode = true;

      // CY 가 울산정일부두(6P42) 인 경우 : 컨테이너번호 옵션
      // ed_cntrNo1.mandatory = "false";
      // ed_cntrNo1.validExp="컨테이너번호:no";
      // ed_cntrNo1.Text = "";
      ed_cntrNo1.setMandatory(false);
      ed_cntrNo1.setValue("");
    } else if (ed_transDstFrom1.getValue() == "6P14" || ed_transDstFrom1.getValue() == "6P12") {
      //  CY 가 허치슨감만T(6P14)/HBCT(6P12) 인 경우 : 컨테이너번호 <- ZZZZ1234567
      // ed_cntrNo1.mandatory = "true";
      // ed_cntrNo1.validExp="컨테이너번호:yes";
      // ed_cntrNo1.Text = "ZZZZ1234567";
      ed_cntrNo1.setMandatory(true);
      ed_cntrNo1.setValue("ZZZZ1234567");
    } else if (ed_transDstFrom1.getValue() == "6P42") {
      // CY 가 울산6부두[UCTC] (6P36) 인 경우 : EMPTY
      // ed_cntrNo1.mandatory = "true";
      // ed_cntrNo1.validExp="컨테이너번호:yes";
      // ed_cntrNo1.Text = "EMPTY";
      ed_cntrNo1.setMandatory(true);
      ed_cntrNo1.setValue("EMPTY");
    } else {
      // 기타 작업장 : 컨테이너 필수 입력
      // ed_cntrNo1.mandatory = "true";
      // ed_cntrNo1.validExp="컨테이너번호:yes";
      ed_cntrNo1.setMandatory(true);
    }
    if (ed_transDstFrom1.getValue() == "6P13") {
      // CY 가 PECT(6P36) 인 경우 : 샤시위치정보 필수
      // acb_chassisPosInfo1.mandatory = "true";
      // acb_chassisPosInfo1.validExp="샤시위치정보:yes";
    } else {
      // 기타 작업장 : 샤시위치정보 선택
      // acb_chassisPosInfo1.mandatory = "false";
      // acb_chassisPosInfo1.validExp="샤시위치정보:no";
    }
  }
  if (!$c.gus.cfIsNull($p, scwin.hid_transDstFromWrkPlCd1)) {
    if (scwin.hid_transDstFromWrkPlCd1 == DsConstants.WRK_PL_CLS_CD_PORT) {
      // CY 가 부두인 경우 : OPERATOR 필수 입력
      // ed_shpCoCd1.validExp="OPERATOR:yes";
    }
  }
  if (!$c.gus.cfIsNull($p, ed_transDstFrom1.getValue())) {
    // 수신자 <- 출발지 설정
    scwin.hid_rcv1 = ed_transDstFrom1.getValue();
  } else {
    scwin.hid_rcv1 = "";
  }
};
